1211 // strongSIVtest -
1212 // From the paper, Practical Dependence Testing, Section 4.2.1
1213 //
1214 // When we have a pair of subscripts of the form [c1 + a*i] and [c2 + a*i],
1215 // where i is an induction variable, c1 and c2 are loop invariant,
1216 //  and a is a constant, we can solve it exactly using the Strong SIV test.
1217 //
1218 // Can prove independence. Failing that, can compute distance (and direction).
1219 // In the presence of symbolic terms, we can sometimes make progress.
1220 //
1221 // If there's a dependence,
1222 //
1223 //    c1 + a*i = c2 + a*i'
1224 //
1225 // The dependence distance is
1226 //
1227 //    d = i' - i = (c1 - c2)/a
1228 //
1229 // A dependence only exists if d is an integer and abs(d) <= U, where U is the
1230 // loop's upper bound. If a dependence exists, the dependence direction is
1231 // defined as
1232 //
1233 //                { < if d > 0
1234 //    direction = { = if d = 0
1235 //                { > if d < 0
1236 //
1237 // Return true if dependence disproved.
1238 bool DependenceInfo::strongSIVtest(const SCEVAddRecExpr *Src,
1239                                    const SCEVAddRecExpr *Dst, unsigned Level,
1240                                    FullDependence &Result,
1241                                    bool UnderRuntimeAssumptions) {
1242   if (!isDependenceTestEnabled(DependenceTestType::StrongSIV))
1243     return false;
1244 
1245   if (!Src->hasNoSignedWrap() || !Dst->hasNoSignedWrap())
1246     return false;
1247 
1248   const SCEV *Coeff = Src->getStepRecurrence(*SE);
1249   assert(Coeff == Dst->getStepRecurrence(*SE) &&
1250          "Expecting same coefficient in Strong SIV test");
1251   const SCEV *SrcConst = Src->getStart();
1252   const SCEV *DstConst = Dst->getStart();
1253   LLVM_DEBUG(dbgs() << "\tStrong SIV test\n");
1254   LLVM_DEBUG(dbgs() << "\t    Coeff = " << *Coeff);
1255   LLVM_DEBUG(dbgs() << ", " << *Coeff->getType() << "\n");
1256   LLVM_DEBUG(dbgs() << "\t    SrcConst = " << *SrcConst);
1257   LLVM_DEBUG(dbgs() << ", " << *SrcConst->getType() << "\n");
1258   LLVM_DEBUG(dbgs() << "\t    DstConst = " << *DstConst);
1259   LLVM_DEBUG(dbgs() << ", " << *DstConst->getType() << "\n");
1260   ++StrongSIVapplications;
1261   assert(0 < Level && Level <= CommonLevels && "level out of range");
1262   Level--;
1263 
1264   // First try to prove independence based on the ranges of the two subscripts.
1265   ConstantRange SrcRange = SE->getSignedRange(Src);
1266   ConstantRange DstRange = SE->getSignedRange(Dst);
1267   if (SrcRange.intersectWith(DstRange).isEmptySet()) {
1268     ++StrongSIVindependence;
1269     ++StrongSIVsuccesses;
1270     return true;
1271   }
1272 
1273   const SCEV *Delta = minusSCEVNoSignedOverflow(SrcConst, DstConst, *SE);
1274   if (!Delta) {
1275     Result.Consistent = false;
1276     return false;
1277   }
1278   LLVM_DEBUG(dbgs() << "\t    Delta = " << *Delta);
1279   LLVM_DEBUG(dbgs() << ", " << *Delta->getType() << "\n");
1280 
1281   // Can we compute distance?
1282   if (isa<SCEVConstant>(Delta) && isa<SCEVConstant>(Coeff)) {
1283     APInt ConstDelta = cast<SCEVConstant>(Delta)->getAPInt();
1284     APInt ConstCoeff = cast<SCEVConstant>(Coeff)->getAPInt();
1285     APInt Distance = ConstDelta; // these need to be initialized
1286     APInt Remainder = ConstDelta;
1287     APInt::sdivrem(ConstDelta, ConstCoeff, Distance, Remainder);
1288     LLVM_DEBUG(dbgs() << "\t    Distance = " << Distance << "\n");
1289     LLVM_DEBUG(dbgs() << "\t    Remainder = " << Remainder << "\n");
1290     // Make sure Coeff divides Delta exactly
1291     if (Remainder != 0) {
1292       // Coeff doesn't divide Distance, no dependence
1293       ++StrongSIVindependence;
1294       ++StrongSIVsuccesses;
1295       return true;
1296     }
1297     Result.DV[Level].Distance = SE->getConstant(Distance);
1298     if (Distance.sgt(0))
1299       Result.DV[Level].Direction &= Dependence::DVEntry::LT;
1300     else if (Distance.slt(0))
1301       Result.DV[Level].Direction &= Dependence::DVEntry::GT;
1302     else
1303       Result.DV[Level].Direction &= Dependence::DVEntry::EQ;
1304     ++StrongSIVsuccesses;
1305   } else if (Delta->isZero()) {
1306     // Check if coefficient could be zero. If so, 0/0 is undefined and we
1307     // cannot conclude that only same-iteration dependencies exist.
1308     // When coeff=0, all iterations access the same location.
1309     if (SE->isKnownNonZero(Coeff)) {
1310       LLVM_DEBUG(
1311           dbgs() << "\t    Coefficient proven non-zero by SCEV analysis\n");
1312     } else {
1313       // Cannot prove at compile time, would need runtime assumption.
1314       if (UnderRuntimeAssumptions) {
1315         const SCEVPredicate *Pred = SE->getComparePredicate(
1316             ICmpInst::ICMP_NE, Coeff, SE->getZero(Coeff->getType()));
1317         Result.Assumptions = Result.Assumptions.getUnionWith(Pred, *SE);
1318         LLVM_DEBUG(dbgs() << "\t    Added runtime assumption: " << *Coeff
1319                           << " != 0\n");
1320       } else {
1321         // Cannot add runtime assumptions, this test cannot handle this case.
1322         // Let more complex tests try.
1323         LLVM_DEBUG(dbgs() << "\t    Would need runtime assumption " << *Coeff
1324                           << " != 0, but not allowed. Failing this test.\n");
1325         return false;
1326       }
1327     }
1328     // Since 0/X == 0 (where X is known non-zero or assumed non-zero).
1329     Result.DV[Level].Distance = Delta;
1330     Result.DV[Level].Direction &= Dependence::DVEntry::EQ;
1331     ++StrongSIVsuccesses;
1332   } else {
1333     if (Coeff->isOne()) {
1334       LLVM_DEBUG(dbgs() << "\t    Distance = " << *Delta << "\n");
1335       Result.DV[Level].Distance = Delta; // since X/1 == X
1336     } else {
1337       Result.Consistent = false;
1338     }
1339 
1340     // maybe we can get a useful direction
1341     bool DeltaMaybeZero = !SE->isKnownNonZero(Delta);
1342     bool DeltaMaybePositive = !SE->isKnownNonPositive(Delta);
1343     bool DeltaMaybeNegative = !SE->isKnownNonNegative(Delta);
1344     bool CoeffMaybePositive = !SE->isKnownNonPositive(Coeff);
1345     bool CoeffMaybeNegative = !SE->isKnownNonNegative(Coeff);
1346     // The double negatives above are confusing.
1347     // It helps to read !SE->isKnownNonZero(Delta)
1348     // as "Delta might be Zero"
1349     unsigned NewDirection = Dependence::DVEntry::NONE;
1350     if ((DeltaMaybePositive && CoeffMaybePositive) ||
1351         (DeltaMaybeNegative && CoeffMaybeNegative))
1352       NewDirection = Dependence::DVEntry::LT;
1353     if (DeltaMaybeZero)
1354       NewDirection |= Dependence::DVEntry::EQ;
1355     if ((DeltaMaybeNegative && CoeffMaybePositive) ||
1356         (DeltaMaybePositive && CoeffMaybeNegative))
1357       NewDirection |= Dependence::DVEntry::GT;
1358     if (NewDirection < Result.DV[Level].Direction)
1359       ++StrongSIVsuccesses;
1360     Result.DV[Level].Direction &= NewDirection;
1361   }
1362   return false;
1363 }
