1365 // weakCrossingSIVtest -
1366 // From the paper, Practical Dependence Testing, Section 4.2.2
1367 //
1368 // When we have a pair of subscripts of the form [c1 + a*i] and [c2 - a*i],
1369 // where i is an induction variable, c1 and c2 are loop invariant,
1370 // and a is a constant, we can solve it exactly using the
1371 // Weak-Crossing SIV test.
1372 //
1373 // Given c1 + a*i = c2 - a*i', we can look for the intersection of
1374 // the two lines, where i = i', yielding
1375 //
1376 //    c1 + a*i = c2 - a*i
1377 //    2a*i = c2 - c1
1378 //    i = (c2 - c1)/2a
1379 //
1380 // If i < 0, there is no dependence.
1381 // If i > upperbound, there is no dependence.
1382 // If i = 0 (i.e., if c1 = c2), there's a dependence with distance = 0.
1383 // If i = upperbound, there's a dependence with distance = 0.
1384 // If i is integral, there's a dependence (all directions).
1385 // If the non-integer part = 1/2, there's a dependence (<> directions).
1386 // Otherwise, there's no dependence.
1387 //
1388 // Can prove independence. Failing that,
1389 // can sometimes refine the directions.
1390 // Can determine iteration for splitting.
1391 //
1392 // Return true if dependence disproved.
1393 bool DependenceInfo::weakCrossingSIVtest(const SCEV *Coeff,
1394                                          const SCEV *SrcConst,
1395                                          const SCEV *DstConst,
1396                                          const Loop *CurSrcLoop,
1397                                          const Loop *CurDstLoop, unsigned Level,
1398                                          FullDependence &Result) const {
1399   if (!isDependenceTestEnabled(DependenceTestType::WeakCrossingSIV))
1400     return false;
1401 
1402   LLVM_DEBUG(dbgs() << "\tWeak-Crossing SIV test\n");
1403   LLVM_DEBUG(dbgs() << "\t    Coeff = " << *Coeff << "\n");
1404   LLVM_DEBUG(dbgs() << "\t    SrcConst = " << *SrcConst << "\n");
1405   LLVM_DEBUG(dbgs() << "\t    DstConst = " << *DstConst << "\n");
1406   ++WeakCrossingSIVapplications;
1407   assert(0 < Level && Level <= CommonLevels && "Level out of range");
1408   Level--;
1409   Result.Consistent = false;
